<template>
 <div class="container">
     <div class="row">
        <div class="col col-sm-6 col-xs-12"> <v-calendar :attributes='attrs' is-single-paned  is-expanded> </v-calendar></div>
        <div class="col col-sm-6 col-xs-12"> <div>events</div></div>
     </div>
</div> 
</template>

<script>
import Nav from './main/Nav.vue';

export default {
  name: 'Events',
   data() {
    return {
         attrs: [
            {
            key: 'today',
            dates: { weekdays: [ 2] },
            highlight: {
                backgroundColor: '#ff8080',
                
            },
            // Just use a normal style
            contentStyle: {
                color: '#fafafa',
            },
            contentHoverStyle: {
                color: 'black'
            },
            // Our new popover here
            popover: {
                label: 'Cantos!',
            }
            },
            {
                key: 'salida',
                dates: [new Date(2018, 0, 12)],
                highlight: {
                    backgroundColor: 'yellow',
            } 
            }
      ],
    };
  },
  components:{
    'nav-component': Nav
  }
}
</script>

<style  lang="scss">
@import '../assets/main';

.container {
    margin-top: 100px;
}
.c-pane-container {
    position: relative;
    width: 100%!important;
    height: 70vh;

}
    .c-day{
        height: 70px!important;
    }

    .c-day-content{
        border-radius: 0px!important;
    }
</style>



