<template>
  <div>
    <div v-if="userStore.authUser !== null && userStore.authUser.access_token">
         <div class="container">
            <h1>dashboard</h1>
            <button class="btn" v-on:click="handleLogout()">logout</button>
        </div>
    </div>
      <p>{{message}}</p>
     <input type="text"  v-model="message" placeholder="Edit text">
     <button class="btn" @click="changeMessage">Change</button>
     
  </div>

</template>

<script>
import Nav from '../main/Nav.vue';
import {bus} from '../../main';
import {mapState} from 'vuex';

export default {
  name: 'Dashboard',
  components:{
    'nav-component': Nav
  },
  props: ['text'],
  data () {
    return {
        message: ''
    }
  },
   computed: {
    ...mapState({
      userStore: state => state.userStore
    })
  },
  methods: {
      handleLogout(){
          this.$store.dispatch('clearAuthUser')
          window.localStorage.removeItem('authUser')
          this.$router.push({path: '/member'})
      },
      changeMessage: function(){
          var newMessage = this.message;
          console.log(newMessage)
          // this.$emit('messageChanged', this.message);
          this.$bus.$emit('messageChanged', newMessage);

      },
      getData: function(){
        this.$http.get('http://iglesiadecristoenelgin.com/Test/api.php').then(response => { 
            console.log(response)
        });
      }
  },
  mounted(){
    this.getData();
  }
}
</script>

<style lang="scss">

</style>



