<template>
  <div id="app">
    <div class="roww">
    <div class="left-view "><nav-component></nav-component></div>
      <div class="right-view "> 
        <transition name="fade">
        <router-view />
      </transition>
      </div>

    </div>
   
  </div>
</template>

<script>

import Nav from './components/main/Nav.vue'

export default {
  name: 'app',
  data () {
    return {
      msg: 'Welcome to Your Vue.js App'
    }
  },
  components: {
    'nav-component': Nav
  },
  methods: {
       afterEnter: function( el ) {
      // how to have this per-route
      console.log( 'Route entered' );
    }
  },
  created () {
    const userObj = JSON.parse(window.localStorage.getItem('authUser'))
    this.$store.dispatch('setUserObject', userObj)
  }
}
</script>

<style lang="scss">
@import './assets/main';

.fade-enter-active, .fade-leave-active {
  transition-property: opacity;
  transition-duration: .25s;
}

.fade-enter-active {
  transition-delay: .25s;
}

.fade-enter, .fade-leave-active {
  opacity: 0
}

#app {
  font-weight:300;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  color: #2c3e50;
  margin-top: 0px!important;
  width: 100%;

  .right-view {
   width: 100%;
   padding-left: 110px;
   height: 100vh;
   background: $gradient;
   
  }

}
.roww {
   display: flex;
    align-items: stretch;
}

section {
  height: 100vh;
}

div#sidebar:hover{
      width: 250px;
}
#mylist {

  max-height: 50vh;
  overflow-y: scroll;
  width: 100%;

  div.core-menu:hover {
    z-index: 999;

    .core-menu a {
      z-index: 999;
    }
  }
 

  .hd h1{
    border: solid black 1px;
    margin: 5px;
    margin-left: 0%;
    padding: 10px;
    left: 30%;
    font-size: 30px;
    
  } 


  .shrink h1{
      font-size: 20px;
      padding-top: 10px;
      height: 70px;
      
  }
  .pllist {
    max-height: 150px;
    overflow-y: scroll;
  }

 li {
      font-size: 20px;
      list-style-type: none;
      text-align: left;
      left: 10%;
      position: relative;
      width: 90%;
  }

}
</style>



