</div> 
</template>

<script>

// import Dashboard from "../member-pages/Dashboard.vue"
import {bus} from '../../main';

export default {
  name: 'Conviction',
  // props: ['message'],
  data(){
    return {
        message: 'Dismessage'
    }
  },
  components: {
    // "dashboard-component": Dashboard
  },
  created () {
    this.$bus.$on('messageChanged', (data) => {
      console.log(this.message)
       this.message = data;
       console.log("messaged has changed!!")
    })
  }
}
</script>

