<template>
 <div >
     <div class="limiter member">
		<div class="container-login100">
			<div class="wrap-login100">
				<form class="login100-form validate-form" v-on:submit.prevent="handleLoginFormSubmit()">
					<span class="login100-form-title">	
						 <i class="fas fa-user fa-2x"></i>
					</span>

					<div class="wrap-input100 validate-input" data-validate = "Valid email is: a@b.c">
						<input class="input100" type="text" name="email" v-model="login.email" >
						<span class="focus-input100" data-placeholder="Email"></span>
					</div>

					<div class="wrap-input100 validate-input" data-validate="Enter password">
						<span class="btn-show-pass">
							<i class="fas fa-eye eye"></i>
                            <i class="fas fa-eye-slash eye-slash hide"></i>
						</span>
						<input class="input100" type="password" name="pass" v-model="login.password">
						<span class="focus-input100" data-placeholder="Password"></span>
					</div>

					<div class="container-login100-form-btn">
						<div class="wrap-login100-form-btn">
							<div class="login100-form-bgbtn"></div>
							<button class="login100-form-btn">
								Login
							</button>
						</div>
					</div>
				</form>
			</div>
		</div>
	</div>

    <dash-component :msg="message"></dash-component>
    
</div> 
</template>

<script>
import Nav from './main/Nav.vue';
import Dashboard from './member-pages/Dashboard.vue';
import { loginUrl, getHeader, userUrl } from '../config';
import {clientId, clientSecret} from '../env';
import {mapState} from 'vuex';


export default {
  name: 'Member',
  components:{
    'nav-component': Nav,
    'dash-component': Dashboard
  },
  data () {
    return {
      login: {
        email: '',
        password: ''
      }
    }
  },
  computed: {
    ...mapState({
      userStore: state => state.userStore
    })
  },
  methods: {
    handleLoginFormSubmit(){
      const postData = {
        grant_type: 'password',
        client_id: clientId,
        client_secret: clientSecret,
        username: this.login.email,
        password: this.login.password,
        scope: ''

        }

      const authUser = {}
      this.$http.post(loginUrl, postData)
        .then(response => {
          if (response.status ===200) {
              authUser.access_token = response.data.access_token
              authUser.refresh_token = response.data.refresh_token
              window.localStorage.setItem('authUser', JSON.stringify(authUser))
              this.$http.get(userUrl, {headers: getHeader()})
                .then(response => {
                    authUser.email = response.body.email
                    authUser.name = response.body.name
                    window.localStorage.setItem('authUser', JSON.stringify(authUser))
                    this.$store.dispatch('setUserObject', authUser)
                    this.$router.push({path:"/member/dashboard"})
                })

          }
        })
    },
    animation() {
  (function ($) {
    "use strict";


    /*==================================================================
    [ Focus input ]*/
    $('.input100').each(function(){
        $(this).on('blur', function(){
            if($(this).val().trim() != "") {
                $(this).addClass('has-val');
            }
            else {
                $(this).removeClass('has-val');
            }
        })    
    })
  
  
    /*==================================================================
    [ Validate ]*/
    var input = $('.validate-input .input100');

    $('.validate-form').on('submit',function(){
        var check = true;

        for(var i=0; i<input.length; i++) {
            if(validate(input[i]) == false){
                showValidate(input[i]);
                check=false;
            }
        }

        return check;
    });


    $('.validate-form .input100').each(function(){
        $(this).focus(function(){
           hideValidate(this);
        });
    });

    function validate (input) {
        if($(input).attr('type') == 'email' || $(input).attr('name') == 'email') {
            if($(input).val().trim().match(/^([a-zA-Z0-9_\-\.]+)@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.)|(([a-zA-Z0-9\-]+\.)+))([a-zA-Z]{1,5}|[0-9]{1,3})(\]?)$/) == null) {
                return false;
            }
        }
        else {
            if($(input).val().trim() == ''){
                return false;
            }
        }
    }

    function showValidate(input) {
        var thisAlert = $(input).parent();

        $(thisAlert).addClass('alert-validate');
    }

    function hideValidate(input) {
        var thisAlert = $(input).parent();

        $(thisAlert).removeClass('alert-validate');
    }
    
    /*==================================================================
    [ Show pass ]*/
    var showPass = 0;
    $('.btn-show-pass').on('click', function(){
        $(".eye-slash").toggleClass("hide");
        $(".eye").toggleClass("hide");
        
        if(showPass == 0) {
            $(this).next('input').attr('type','text');
            showPass = 1;
        }
        else {
            $(this).next('input').attr('type','password');
            showPass = 0;
        }
    });


})(jQuery);

      }
  },
  mounted(){
      this.animation();
  },
  created (){
    const postData = {
      grant_type: 'password',
      client_id: 2,
      client_secret: '',
      username: this.login.email,
      password: this.login.password,
      scope: ''

    }

    this.$http.post("http://localhost:8000/oauth/token", postData)
    .then(response => {
      const header = {
        'Accept': 'application/json',
        'Authorization': 'Bearer ' + response.body.access_token
      }
      this.$http.get("http://localhost:8000/api/user", {headers: header})
      .then(response => {
      })
    })
  }
}
</script>

<style  lang="scss">
    @import '../assets/main';


    .fa-user {
        color: white;
        margin: 0px 0 30px 0;
        border: 2px solid #f2f2f2;
        border-radius: 100%;
        padding: 20px;
        opacity: .8;
        background: $gradient;
    }
    .hide {
        display: none;
    }



</style>



