<template>
 <div >
     <div class="container">
       <div class="row">
            <div class="col col-sm-3 box">
                <router-link to="/growth/study"><img src="../assets/img/intro/tabs/iconcircle-01-01.svg" alt=""></router-link>
            </div>
            <div class="col col-sm-3 box">
                <router-link to="/growth/hymns"><img src="../assets/img/intro/tabs/iconcircle-01-01.svg" alt=""></router-link>
            </div>
            <div class="col col-sm-3 box">
                <router-link to="/growth/videos"><img src="../assets/img/intro/tabs/iconcircle-01-01.svg" alt=""></router-link>
            </div>
     
       </div>
           
     </div>
</div> 
</template>

<script>
import Nav from './main/Nav.vue';

export default {
  name: 'Growth',
  components:{
    'nav-component': Nav
  }
}
</script>

<style lang="scss" scoped>
@import '../assets/main';
    div{
        background: $gradient;
        height: 100vh;
    }
    .box {
        height: 300px;
        margin: 150px 50px 0 0;
        left: 100px;
        transition: margin .3s;
        border: solid rgba(255, 255, 255, 0.404) 1px;
        border-radius: 10px;
    }

    .box:hover {
        margin-top: 145px;
        -webkit-box-shadow: 2px 2px 5px 2px rgba(0,0,0,.3);
        -moz-box-shadow: 2px 2px 5px 2px rgba(0,0,0,.3);
        box-shadow: 2px 2px 5px 2px rgba(0,0,0,.3);
    }
</style>




